/**
 * Provides previews for moving shapes when moving.
 *
 */
export default class MovePreview {
    static $inject: string[];
    /**
     * @param eventBus
     * @param canvas
     * @param styles
     * @param previewSupport
     */
    constructor(eventBus: EventBus, canvas: Canvas, styles: Styles, previewSupport: PreviewSupport);
    /**
     * Make an element draggable.
     *
     * @param context
     * @param element
     * @param addMarker
     */
    makeDraggable: (context: any, element: Element, addMarker: boolean) => void;
}

type Element = import("../../model/Types.js").Element;
type Canvas = import("../../core/Canvas.js").default;
type EventBus = import("../../core/EventBus.js").default;
type PreviewSupport = import("../preview-support/PreviewSupport.js").default;
type Styles = import("../../draw/Styles.js").default;